describe('Array modifiers', () => {
  it('should infer string array (string[])', () => {
    type Result = InferType<'string[]'>;

    const value: Result = [
      'a',
      'b',
      'c',
    ];

    const schema = createType('string[]');
    expect(
      schema.isValid([
        'a',
        'b',
      ]),
    ).toBe(true);
    expect(schema.isValid([])).toBe(true);
    expect(
      schema.isValid([
        1,
        2,
      ]),
    ).toBe(false);
  });

  it('should infer number array (number[])', () => {
    type Result = InferType<'number[]'>;

    const value: Result = [
      1,
      2,
      3,
    ];

    const schema = createType('number[]');
    expect(
      schema.isValid([
        1,
        2,
        3,
      ]),
    ).toBe(true);
    expect(
      schema.isValid([
        '1',
        '2',
      ]),
    ).toBe(false);
  });

  it('should infer optional array (string[]?) in object context', () => {
    type Result = InferType<'string[]?'>;

    const arr: Result = ['a'];
    const undef: Result = undefined;

    // Optional arrays work in object context
    const schema = createModel({
      items: 'string[]?',
    });
    expect(schema.isValid({})).toBe(true);
    expect(schema.isValid({ items: ['a'] })).toBe(true);
    expect(schema.isValid({ items: undefined })).toBe(true);
  });
});

