/**
 * Type inference tests for the schema system.
 *
 * These tests verify that TypeScript correctly infers types from schema definitions.
 * They use runtime checks to ensure the inferred types work correctly with actual values.
 */
import { describe, expect, it } from 'vitest';
import { stringEnum } from '../../helpers/type-utils';
import { InferType } from '../infer-type';
import { createModel, createType } from '../schema';

describe('Type Inference', () => {
  describe('Primitive string definitions', () => {
    it('should infer string type', () => {
      const schema = createType('string');
      type Result = InferType<'string'>;

      // Type check - if this compiles, the type is correct
      const value: Result = 'hello';
      expect(schema.isValid(value)).toBe(true);
      expect(schema.isValid(123)).toBe(false);
    });

    it('should infer number type', () => {
      const schema = createType('number');
      type Result = InferType<'number'>;

      const value: Result = 42;
      expect(schema.isValid(value)).toBe(true);
      expect(schema.isValid('42')).toBe(false);
    });

    it('should infer boolean type', () => {
      const schema = createType('boolean');
      type Result = InferType<'boolean'>;

      const value: Result = true;
      expect(schema.isValid(value)).toBe(true);
      expect(schema.isValid(1)).toBe(false);
    });

    it('should infer null type', () => {
      const schema = createType('null');
      type Result = InferType<'null'>;

      const value: Result = null;
      expect(schema.isValid(value)).toBe(true);
      expect(schema.isValid(undefined)).toBe(false);
    });

    it('should infer undefined type', () => {
      const schema = createType('undefined');
      type Result = InferType<'undefined'>;

      const value: Result = undefined;
      expect(schema.isValid(value)).toBe(true);
      expect(schema.isValid(null)).toBe(false);
    });

    it('should infer date type', () => {
      const schema = createType('date');
      type Result = InferType<'date'>;

      const value: Result = new Date();
      expect(schema.isValid(value)).toBe(true);
      expect(schema.isValid('2025-01-01')).toBe(false);
    });

    it('should infer function type', () => {
      const schema = createType('function');
      type Result = InferType<'function'>;

      const value: Result = () => {};
      expect(schema.isValid(value)).toBe(true);
      expect(schema.isValid('function')).toBe(false);
    });

    it('should infer object type', () => {
      const schema = createType('object');
      type Result = InferType<'object'>;

      const value: Result = { foo: 'bar' };
      expect(schema.isValid(value)).toBe(true);
      expect(schema.isValid([])).toBe(false);
    });

    it('should infer unknown type', () => {
      const schema = createType('unknown');
      type Result = InferType<'unknown'>;

      // Unknown accepts anything
      const value: Result = 'anything';
      expect(schema.isValid(value)).toBe(true);
      expect(schema.isValid(123)).toBe(true);
      expect(schema.isValid(null)).toBe(true);
    });

    it('should infer any type', () => {
      const schema = createType('any');
      type Result = InferType<'any'>;

      const value: Result = { anything: true };
      expect(schema.isValid(value)).toBe(true);
    });
  });

  describe('Optional modifiers', () => {
    it('should infer optional string (string?) in object context', () => {
      type Result = InferType<'string?'>;

      // Type allows string or undefined
      const str: Result = 'hello';
      const undef: Result = undefined;

      // Optional types are primarily for object properties
      const schema = createModel({
        required: 'string',
        optional: 'string?',
      });
      expect(schema.isValid({ required: 'test' })).toBe(true);
      expect(
        schema.isValid({
          required: 'test',
          optional: 'value',
        }),
      ).toBe(true);
      expect(
        schema.isValid({
          required: 'test',
          optional: undefined,
        }),
      ).toBe(true);
    });

    it('should infer optional number (number?) in object context', () => {
      type Result = InferType<'number?'>;

      const num: Result = 42;
      const undef: Result = undefined;

      const schema = createModel({
        value: 'number?',
      });
      expect(schema.isValid({})).toBe(true);
      expect(schema.isValid({ value: 42 })).toBe(true);
      expect(schema.isValid({ value: undefined })).toBe(true);
    });
  });

  describe('Array modifiers', () => {
    it('should infer string array (string[])', () => {
      type Result = InferType<'string[]'>;

      const value: Result = [
        'a',
        'b',
        'c',
      ];

      const schema = createType('string[]');
      expect(
        schema.isValid([
          'a',
          'b',
        ]),
      ).toBe(true);
      expect(schema.isValid([])).toBe(true);
      expect(
        schema.isValid([
          1,
          2,
        ]),
      ).toBe(false);
    });

    it('should infer number array (number[])', () => {
      type Result = InferType<'number[]'>;

      const value: Result = [
        1,
        2,
        3,
      ];

      const schema = createType('number[]');
      expect(
        schema.isValid([
          1,
          2,
          3,
        ]),
      ).toBe(true);
      expect(
        schema.isValid([
          '1',
          '2',
        ]),
      ).toBe(false);
    });

    it('should infer optional array (string[]?) in object context', () => {
      type Result = InferType<'string[]?'>;

      const arr: Result = ['a'];
      const undef: Result = undefined;

      // Optional arrays work in object context
      const schema = createModel({
        items: 'string[]?',
      });
      expect(schema.isValid({})).toBe(true);
      expect(schema.isValid({ items: ['a'] })).toBe(true);
      expect(schema.isValid({ items: undefined })).toBe(true);
    });
  });

  describe('Object definitions', () => {
    it('should infer simple object properties', () => {
      const schema = createModel({
        name: 'string',
        age: 'number',
      });

      type Result = InferType<typeof schema>;

      // Compile-time type check
      const value: Result = {
        name: 'John',
        age: 30,
      };

      expect(
        schema.isValid({
          name: 'John',
          age: 30,
        }),
      ).toBe(true);
      expect(schema.isValid({ name: 'John' })).toBe(false);
      expect(
        schema.isValid({
          name: 123,
          age: 30,
        }),
      ).toBe(false);
    });

    it('should infer object with optional properties', () => {
      const schema = createModel({
        required: 'string',
        optional: 'number?',
      });

      expect(schema.isValid({ required: 'test' })).toBe(true);
      expect(
        schema.isValid({
          required: 'test',
          optional: 42,
        }),
      ).toBe(true);
      expect(
        schema.isValid({
          required: 'test',
          optional: undefined,
        }),
      ).toBe(true);
      expect(schema.isValid({})).toBe(false);
    });

    it('should infer nested objects via createType', () => {
      const schema = createType({
        properties: {
          user: {
            properties: {
              name: 'string',
              email: 'string',
            },
          },
        },
      });

      expect(
        schema.isValid({
          user: {
            name: 'John',
            email: 'john@example.com',
          },
        }),
      ).toBe(true);

      expect(
        schema.isValid({
          user: { name: 'John' },
        }),
      ).toBe(false);
    });
  });

  describe('Enum definitions', () => {
    it('should infer enum from stringEnum helper', () => {
      const StatusValues = stringEnum('pending', 'active', 'completed');
      const schema = createType({ enum: StatusValues });

      expect(schema.isValid('pending')).toBe(true);
      expect(schema.isValid('active')).toBe(true);
      expect(schema.isValid('invalid')).toBe(false);
    });

    it('should infer enum with inline values', () => {
      const schema = createType({
        enum: [
          'draft',
          'published',
          'archived',
        ] as const,
      });

      expect(schema.isValid('draft')).toBe(true);
      expect(schema.isValid('published')).toBe(true);
      expect(schema.isValid('unknown')).toBe(false);
    });

    it('should work in object properties', () => {
      const schema = createModel({
        status: {
          enum: [
            'on',
            'off',
          ] as const,
        },
        name: 'string',
      });

      expect(
        schema.isValid({
          status: 'on',
          name: 'test',
        }),
      ).toBe(true);
      expect(
        schema.isValid({
          status: 'maybe',
          name: 'test',
        }),
      ).toBe(false);
    });
  });

  describe('Union definitions', () => {
    it('should infer simple union', () => {
      const schema = createType({
        union: [
          'string',
          'number',
        ],
      });

      expect(schema.isValid('hello')).toBe(true);
      expect(schema.isValid(42)).toBe(true);
      expect(schema.isValid(true)).toBe(false);
    });

    it('should infer union with null', () => {
      const schema = createType({
        union: [
          'string',
          'null',
        ],
      });

      expect(schema.isValid('hello')).toBe(true);
      expect(schema.isValid(null)).toBe(true);
      expect(schema.isValid(undefined)).toBe(false);
    });

    it('should work in object properties', () => {
      const schema = createModel({
        value: {
          union: [
            'string',
            'number',
            'null',
          ],
        },
      });

      expect(schema.isValid({ value: 'text' })).toBe(true);
      expect(schema.isValid({ value: 123 })).toBe(true);
      expect(schema.isValid({ value: null })).toBe(true);
      expect(schema.isValid({ value: true })).toBe(false);
    });
  });

  describe('Array/List definitions', () => {
    it('should infer items array', () => {
      const schema = createType({
        items: 'string',
      });

      expect(
        schema.isValid([
          'a',
          'b',
          'c',
        ]),
      ).toBe(true);
      expect(schema.isValid([])).toBe(true);
      expect(
        schema.isValid([
          1,
          2,
          3,
        ]),
      ).toBe(false);
    });

    it('should infer complex items', () => {
      const schema = createType({
        items: {
          properties: {
            id: 'number',
            name: 'string',
          },
        },
      });

      expect(
        schema.isValid([
          {
            id: 1,
            name: 'first',
          },
          {
            id: 2,
            name: 'second',
          },
        ]),
      ).toBe(true);

      expect(schema.isValid([{ id: 1 }])).toBe(false);
    });

    it('should work with list() method', () => {
      const itemSchema = createModel({
        id: 'number',
        value: 'string',
      });

      const listSchema = itemSchema.list();

      expect(
        listSchema.isValid([
          {
            id: 1,
            value: 'a',
          },
          {
            id: 2,
            value: 'b',
          },
        ]),
      ).toBe(true);
    });
  });

  describe('Record definitions', () => {
    it('should infer string record', () => {
      const schema = createType({
        record: 'string',
      });

      expect(
        schema.isValid({
          key1: 'value1',
          key2: 'value2',
        }),
      ).toBe(true);
      expect(schema.isValid({})).toBe(true);
      expect(schema.isValid({ key: 123 })).toBe(false);
    });

    it('should infer number record', () => {
      const schema = createType({
        record: 'number',
      });

      expect(
        schema.isValid({
          a: 1,
          b: 2,
        }),
      ).toBe(true);
      expect(schema.isValid({ a: 'not-number' })).toBe(false);
    });
  });

  describe('Composed schemas (reusing types)', () => {
    it('should allow composing types', () => {
      const AddressSchema = createModel({
        street: 'string',
        city: 'string',
        zip: 'string',
      });

      const PersonSchema = createModel({
        name: 'string',
        address: AddressSchema,
      });

      expect(
        PersonSchema.isValid({
          name: 'John',
          address: {
            street: '123 Main St',
            city: 'NYC',
            zip: '10001',
          },
        }),
      ).toBe(true);

      expect(
        PersonSchema.isValid({
          name: 'John',
          address: {
            street: '123 Main St',
            // missing city and zip
          },
        }),
      ).toBe(false);
    });
  });

  describe('Parse and validation', () => {
    it('should parse and return typed values', () => {
      const schema = createModel({
        id: 'number',
        name: 'string',
        active: 'boolean',
      });

      const result = schema.parse({
        id: 1,
        name: 'test',
        active: true,
      });

      // These should compile without errors
      expect(result.id).toBe(1);
      expect(result.name).toBe('test');
      expect(result.active).toBe(true);
    });

    it('should throw on invalid input', () => {
      const schema = createModel({
        id: 'number',
      });

      expect(() => schema.parse({ id: 'not-a-number' })).toThrow();
    });

    it('should parse lists correctly', () => {
      const schema = createModel({
        value: 'string',
      });

      const result = schema.parseList([
        { value: 'a' },
        { value: 'b' },
      ]);

      expect(result).toHaveLength(2);
      expect(result[0].value).toBe('a');
      expect(result[1].value).toBe('b');
    });
  });

  describe('Edge cases', () => {
    it('should handle deeply nested structures', () => {
      const schema = createType({
        properties: {
          level1: {
            properties: {
              level2: {
                properties: {
                  level3: 'string',
                },
              },
            },
          },
        },
      });

      expect(
        schema.isValid({
          level1: {
            level2: {
              level3: 'deep',
            },
          },
        }),
      ).toBe(true);
    });

    it('should handle empty objects', () => {
      const schema = createModel({});
      expect(schema.isValid({})).toBe(true);
    });

    it('should cache string type definitions', () => {
      const schema1 = createType('string');
      const schema2 = createType('string');

      // Should return cached instance
      expect(schema1).toBe(schema2);
    });

    it('should not cache object definitions', () => {
      const schema1 = createModel({ a: 'string' });
      const schema2 = createModel({ a: 'string' });

      // Object schemas should not be cached
      expect(schema1).not.toBe(schema2);
    });
  });
});

