import { produce } from 'immer';
import { describe, expect, it, vi } from 'vitest';

import { createMachineConfig } from '../helpers';
import { createMachine } from '../machine';

import { createAsyncSlice, createSlice, Slices } from '../slice';

import { AnyAction, METADATA_FIELD_NAME, SliceContext } from '../models';

describe('createMachine', () => {
  const mockLoadUser = vi.fn();
  const mockGetUserID = vi.fn(() => 'user-123');

  const defaultContext = {
    api: { loadUser: mockLoadUser },
    auth: { getUserID: mockGetUserID },
    userID: null,
  } satisfies SliceContext;

  const userSlice = createAsyncSlice({
    id: 'user',
    cache: { policy: 'private' },
    context: defaultContext,
    load: async (id: string, context) => {
      const user = await context.api.loadUser(id);
      return {
        ...user,
        loadedBy: context.auth.getUserID(),
      };
    },
  });

  const counterSlice = createSlice({
    id: 'counter',
    cache: { policy: 'private' },
    initial: { value: 0 },
    reducers: {
      increment: state => {
        state.value += 1;
      },
      add: (state, payload: number) => {
        state.value += payload;
      },
      reset: state => {
        state.value = 0;
      },
    },
  });

  const configSlice = createSlice({
    id: 'config',
    cache: { policy: 'public' },
    initial: { enabled: false },
    reducers: {
      toggle: state => {
        state.enabled = !state.enabled;
      },
    },
  });

  const getMachineConfig = () => {
    return createMachineConfig({
      id: 'testMachine',
      slices: {
        user: userSlice,
        counter: counterSlice,
        config: configSlice,
      },
      context: {
        userID: 'test-user',
        api: { loadUser: mockLoadUser },
        auth: { getUserID: mockGetUserID },
      },
      initial: {
        counter: { value: 10 },
      },
      selectors: {
        doubledCounter: state => state.counter.value * 2,
        userAndCounter: state => {
          return {
            user: state.user.value,
            counter: state.counter.value,
          };
        },
      },
    });
  };

  it('should create a machine with the correct structure', () => {
    const machine = createMachine(getMachineConfig());

    expect(machine.ID).toBe('testMachine');
    expect(machine.reducer).toBeInstanceOf(Function);
    expect(Object.keys(machine.actions)).toEqual([
      'user',
      'counter',
      'config',
    ]);
    expect(Object.keys(machine.actionTypes)).toEqual([
      'user',
      'counter',
      'config',
    ]);
  });

  it('should generate correct action types', () => {
    const machine = createMachine(getMachineConfig());
    expect(machine.actionTypes.counter.increment).toBe(
      '@testMachine/counter/increment',
    );
    expect(machine.actionTypes.user.load).toBe('@testMachine/user/load');
  });

  it('should initialize with the correct initial state, including provided state', () => {
    const config = getMachineConfig();
    const machine = createMachine(config);
    const initialState = machine.getInitialState();

    expect(initialState.counter).toEqual({ value: 10 });
    expect(initialState.config).toEqual({ enabled: false });
    expect(initialState.user).toEqual(Slices.AsyncInitialState(null));
    expect(initialState.doubledCounter).toBe(20);
    expect(initialState[METADATA_FIELD_NAME]).toBeDefined();
  });

  it('should handle sync slice actions correctly', () => {
    const machine = createMachine({
      ...getMachineConfig(),
      initial: undefined,
    });

    machine.provideContext(defaultContext);

    let state = machine.getInitialState();

    expect(state.counter.value).toBe(0);

    const incrementAction = machine.actions.counter.increment();
    state = machine.reducer(state, incrementAction);
    expect(state.counter.value).toBe(1);

    const addAction = machine.actions.counter.add(5);
    state = machine.reducer(state, addAction);
    expect(state.counter.value).toBe(6);
  });

  it('should not mutate state when a reducer does not change it', () => {
    const machine = createMachine(getMachineConfig());
    const initialState = machine.getState();

    const noopAction = { type: 'NO_OP' };
    const nextState = machine.reducer(initialState, noopAction as AnyAction);

    expect(nextState).toBe(initialState);
  });

  describe('Async Slice Reducers', () => {
    const machine = createMachine({
      ...getMachineConfig(),
      initial: undefined,
    });
    const { actions, reducer } = machine;
    let state = machine.getInitialState();

    it('should handle load action', () => {
      const loadAction = actions.user.load('1');
      state = reducer(state, loadAction);
      expect(state.user.loading).toBe(true);
      expect(state.user.failed).toBe(false);
      expect(state.user.error).toBeNull();
    });

    it('should handle success action', () => {
      const loadAction = actions.user.load('1');
      let loadingState = reducer(state, loadAction);
      const successPayload = {
        id: '1',
        name: 'John',
      };
      const successAction = actions.user.success(successPayload);
      const successState = reducer(loadingState, successAction);

      expect(successState.user.loading).toBe(false);
      expect(successState.user.loaded).toBe(true);
      expect(successState.user.value).toEqual(successPayload);
    });

    it('should handle fail action', () => {
      const loadAction = actions.user.load('1');
      let loadingState = reducer(state, loadAction);
      const errorPayload = {
        error: 'Not Found',
        stack: '...',
      };
      const failAction = actions.user.fail(errorPayload);
      const failState = reducer(loadingState, failAction);

      expect(failState.user.loading).toBe(false);
      expect(failState.user.failed).toBe(true);
      expect(failState.user.error).toBe('Not Found');
    });

    it('should handle clear action', () => {
      const successState = produce(state, draft => {
        draft.user.loaded = true;
        draft.user.value = {
          id: '1',
          name: 'John',
        } as any;
      });

      const clearAction = actions.user.clear();
      const clearedState = reducer(successState, clearAction);

      expect(clearedState.user).toEqual(Slices.AsyncInitialState(null));
    });
  });

  it('should compute selectors correctly on state changes', () => {
    const machine = createMachine({
      ...getMachineConfig(),
      initial: undefined,
    });
    let state = machine.getInitialState();
    expect(state.doubledCounter).toBe(0);

    const action = machine.actions.counter.add(10);
    state = machine.reducer(state, action);

    expect(state.counter.value).toBe(10);
    expect(state.doubledCounter).toBe(20);
  });

  it('should provide the correct context to async slices', () => {
    const machine = createMachine(getMachineConfig());
    const context = machine.getContext();
    expect(context.api.loadUser).toBe(mockLoadUser);
    expect(context.auth.getUserID).toBe(mockGetUserID);
  });

  it('should throw if a non-existent slice reducer is called', () => {
    const machine = createMachine(getMachineConfig());
    const state = machine.getInitialState();
    const invalidAction = { type: '@testMachine/nonExistent/action' };
    const nextState = machine.reducer(state, invalidAction as AnyAction);
    expect(nextState).toBe(state);
  });
});

