/**
 * Type inference tests for the schema system.
 *
 * These tests verify that TypeScript correctly infers types from schema definitions.
 * They use runtime checks to ensure the inferred types work correctly with actual values.
 */
import { describe, expect, it } from 'vitest';
import { stringEnum } from '../../helpers/type-utils';
import { InferType } from '../infer-type';
import { createModel, createType } from '../schema';

describe('Type Inference', () => {
  describe('Primitive string definitions', () => {
    it('should infer string type', () => {
      const schema = createType('string');
      type Result = InferType<'string'>;

      // Type check - if this compiles, the type is correct
      const value: Result = 'hello';
      expect(schema.isValid(value)).toBe(true);
      expect(schema.isValid(123)).toBe(false);
    });

    it('should infer number type', () => {
      const schema = createType('number');
      type Result = InferType<'number'>;

      const value: Result = 42;
      expect(schema.isValid(value)).toBe(true);
      expect(schema.isValid('42')).toBe(false);
    });

    it('should infer boolean type', () => {
      const schema = createType('boolean');
      type Result = InferType<'boolean'>;

      const value: Result = true;
      expect(schema.isValid(value)).toBe(true);
      expect(schema.isValid(1)).toBe(false);
    });

    it('should infer null type', () => {
      const schema = createType('null');
      type Result = InferType<'null'>;

      const value: Result = null;
      expect(schema.isValid(value)).toBe(true);
      expect(schema.isValid(undefined)).toBe(false);
    });

    it('should infer undefined type', () => {
      const schema = createType('undefined');
      type Result = InferType<'undefined'>;

      const value: Result = undefined;
      expect(schema.isValid(value)).toBe(true);
      expect(schema.isValid(null)).toBe(false);
    });

    it('should infer date type', () => {
      const schema = createType('date');
      type Result = InferType<'date'>;

      const value: Result = new Date();
      expect(schema.isValid(value)).toBe(true);
      expect(schema.isValid('2025-01-01')).toBe(false);
    });

    it('should infer function type', () => {
      const schema = createType('function');
      type Result = InferType<'function'>;

      const value: Result = () => {};
      expect(schema.isValid(value)).toBe(true);
      expect(schema.isValid('function')).toBe(false);
    });

    it('should infer object type', () => {
      const schema = createType('object');
      type Result = InferType<'object'>;

      const value: Result = { foo: 'bar' };
      expect(schema.isValid(value)).toBe(true);
      expect(schema.isValid([])).toBe(false);
    });

    it('should infer unknown type', () => {
      const schema = createType('unknown');
      type Result = InferType<'unknown'>;

      // Unknown accepts anything
      const value: Result = 'anything';
      expect(schema.isValid(value)).toBe(true);
      expect(schema.isValid(123)).toBe(true);
      expect(schema.isValid(null)).toBe(true);
    });

    it('should infer any type', () => {
      const schema = createType('any');
      type Result = InferType<'any'>;

      const value: Result = { anything: true };
      expect(schema.isValid(value)).toBe(true);
    });
  });

  describe('Optional modifiers', () => {
    it('should infer optional string (string?) in object context', () => {
      type Result = InferType<'string?'>;

      // Type allows string or undefined (compile-time check)
      void ('hello' satisfies Result);
      void (undefined satisfies Result);

      // Optional types are primarily for object properties
      const schema = createModel({
        required: 'string',
        optional: 'string?',
      });
      expect(schema.isValid({ required: 'test' })).toBe(true);
      expect(
        schema.isValid({
          required: 'test',
          optional: 'value',
        }),
      ).toBe(true);
      expect(
        schema.isValid({
          required: 'test',
          optional: undefined,
        }),
      ).toBe(true);
    });

    it('should infer optional number (number?) in object context', () => {
      type Result = InferType<'number?'>;

