        'a',
        'b',
        'c',
      ];

      const schema = createType('string[]');
      expect(
        schema.isValid([
          'a',
          'b',
        ]),
      ).toBe(true);
      expect(schema.isValid([])).toBe(true);
      expect(
        schema.isValid([
          1,
          2,
        ]),
      ).toBe(false);
    });

