        id: 1,
        name: 'test',
        active: true,
      });

      // These should compile without errors
      expect(result.id).toBe(1);
      expect(result.name).toBe('test');
      expect(result.active).toBe(true);
    });

    it('should throw on invalid input', () => {
      const schema = createModel({
        id: 'number',
      });

      expect(() => schema.parse({ id: 'not-a-number' })).toThrow();
    });

    it('should parse lists correctly', () => {
      const schema = createModel({
        value: 'string',
      });

      const result = schema.parseList([
        { value: 'a' },
        { value: 'b' },
      ]);

      expect(result).toHaveLength(2);
      expect(result[0].value).toBe('a');
      expect(result[1].value).toBe('b');
    });
  });

  describe('Edge cases', () => {
    it('should handle deeply nested structures', () => {
      const schema = createType({
        properties: {
          level1: {
            properties: {
              level2: {
                properties: {
                  level3: 'string',
                },
              },
            },
          },
        },
      });

      expect(
        schema.isValid({
          level1: {
            level2: {
              level3: 'deep',
            },
          },
        }),
      ).toBe(true);
    });

    it('should handle empty objects', () => {
      const schema = createModel({});
      expect(schema.isValid({})).toBe(true);
    });

    it('should cache string type definitions', () => {
      const schema1 = createType('string');
      const schema2 = createType('string');

      // Should return cached instance
      expect(schema1).toBe(schema2);
    });

    it('should not cache object definitions', () => {
      const schema1 = createModel({ a: 'string' });
      const schema2 = createModel({ a: 'string' });

      // Object schemas should not be cached
      expect(schema1).not.toBe(schema2);
    });
  });
});

